import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Slider from 'react-slick';
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';
import '../Styles/Global.css';

const FILTER_CATEGORIES = [
  'All', 'Indoor', 'Outdoor', 'Medicinal',
  'Evergreen', 'Flowering', 'Ornamental',
  'Bonsai', 'Plant Tools'
];

const Home = () => {
  const [featuredPlants, setFeaturedPlants] = useState([]);
  const [filteredPlants, setFilteredPlants] = useState([]);
  const [activeCategory, setActiveCategory] = useState('All');

  useEffect(() => {
    const fetchFeatured = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/admin/products/featured');
        setFeaturedPlants(res.data);
        setFilteredPlants(res.data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchFeatured();
  }, []);

  const handleFilter = (cat) => {
    setActiveCategory(cat);
    if (cat === 'All') setFilteredPlants(featuredPlants);
    else setFilteredPlants(featuredPlants.filter(x => x.category === cat));
  };

  const carouselSettings = { dots: true, infinite: true, speed: 500, slidesToShow: 1, slidesToScroll: 1, autoplay: true, autoplaySpeed: 3000, arrows: true };

  return (
    <div className="home-container">
      {/* Carousel */}
      <section className="carousel-wrapper"> {/* unchanged */} </section>

      {/* Featured Plants with Filter */}
      <section className="featured-section">
        <h2>Featured Plants</h2>
        <p className="subheading">Explore our best selections by type</p>

        <div className="filter-buttons">
          {FILTER_CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => handleFilter(cat)}
              className={activeCategory === cat ? 'active' : ''}
            >
              {cat}
            </button>
          ))}
        </div>

        <div className="portfolio-grid">
          {filteredPlants.map(plant => (
            <div className="portfolio-item" key={plant._id}>
              <div className="portfolio-img-wrapper">
                <img src={`http://localhost:5000/uploads/${plant.imageUrl}`} alt={plant.name} />
                <div className="portfolio-hover">
                  <h3>{plant.name}</h3>
                  <p>${plant.price}</p>
                  <a href={`/product/${plant._id}`} className="view-details">View Details</a>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      <footer className="footer"> {/* unchanged */} </footer>
    </div>
  );
};

export default Home;
